import numpy as np

class ConvexHull4D:
    def __init__(self, points):
        self.points = self.validate_points(points)
        self.hull = None

    def validate_points(self, points):
        if not isinstance(points, list) or not points:
            raise ValueError("Input must be a non-empty list of points.")
        for point in points:
            if not isinstance(point, (list, tuple)) or len(point) != 4:
                raise ValueError("Each point must be a list or tuple of four dimensions.")
        return np.array(points)

    def compute_hull(self):
        if len(self.points) < 5:
            raise ValueError("At least 5 points are required to form a convex hull in 4D.")
        self.hull = ConvexHull(self.points)
        return self.get_hull_vertices()

    def get_hull_vertices(self):
        if self.hull is None:
            raise ValueError("Convex hull has not been computed yet.")
        return self.points[self.hull.vertices].tolist()

