    if len(points) < 4:
        return ConvexHullResult(vertices=points, volume=0.0)

    points_array = np.array(points)
    hull = ConvexHull(points_array)

    hull_vertices = points_array[hull.vertices].tolist()
    hull_volume = hull.volume

    return ConvexHullResult(vertices=hull_vertices, volume=hull_volume)

